2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	
5	type QuoteStep = { op: string; items: Item[] };
6	
7	type Damage = { itemType: string; amount: number };
8	
9	type Incident = { cause: string; damages: Damage[] };
10	
11	type ClaimStep = { op: string; policy: number; incident: Incident };
12	
13	type Step = QuoteStep | ClaimStep;
14	
15	type Customer = { yearsWithMHPCO: number };
16	
17	type Scenario = {
18	  customer: Customer;
19	  steps: Step[];
20	};
21	
22	type QuoteResult = { premium: number };
23	
24	type ClaimResult = { payout: number; remainingCap: number };
25	
26	type StepResult = QuoteResult | ClaimResult;
27	
28	type ScenarioResult = {
29	  results: StepResult[];
30	};
31	
32	const BASE_PREMIUMS: Record<string, number> = {
33	  sword: 100,
34	  amulet: 60,
35	  staff: 80,
36	  potion: 40,
37	  rune: 25,
38	  moonstone: 25,
39	};
40	
41	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
42	const PROCESSING_FEE = 5;
43	
44	const BLOCK_SIZE = 3;
45	const BLOCK_BASE_PREMIUM = 60;
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	
49	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
51	
52	const LOYALTY_DISCOUNT_RATE = 0.2;
53	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
54	
55	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
56	
57	const DEDUCTIBLE = 100;
58	const PAYOUT_CAP = 2000;
59	
60	const countItemsByType = (items: Item[]): Map<string, number> => {
61	  const counts = new Map<string, number>();
62	  for (const item of items) {
63	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
64	  }
65	  return counts;
66	};
67	
68	const basePremiumForGroup = (type: string, count: number): number =>
69	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
70	
71	const calculateTotalBasePremium = (items: Item[]): number =>
72	  [...countItemsByType(items)].reduce(
73	    (total, [type, count]) => total + basePremiumForGroup(type, count),
74	    0,
75	  );
76	
77	const curseSurchargeForItem = (item: Item): number =>
78	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
79	
80	const enchantmentSurchargeForItem = (item: Item): number =>
81	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
82	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
83	    : 0;
84	
85	const sumSurcharges = (
86	  items: Item[],
87	  surchargeForItem: (item: Item) => number,
88	): number =>
89	  items.reduce((total, item) => total + surchargeForItem(item), 0);
90	
91	const policyDiscountRate = (customer: Customer, stepIndex: number): number => {
92	  const loyaltyDiscountRate =
93	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
94	      ? LOYALTY_DISCOUNT_RATE
95	      : 0;
96	  const followUpDiscountRate = stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
97	  return loyaltyDiscountRate + followUpDiscountRate;
98	};
99	
100	const claimStep = (step: ClaimStep): ClaimResult => {
101	  const payout = step.incident.damages[0].amount - DEDUCTIBLE;
102	  return {
103	    payout,
104	    remainingCap: PAYOUT_CAP - payout,
105	  };
106	};
107	
108	const quoteStep = (
109	  step: QuoteStep,
110	  customer: Customer,
111	  stepIndex: number,
112	): QuoteResult => {
113	  const totalBasePremium = calculateTotalBasePremium(step.items);
114	  const firstInsuranceSurcharge =
115	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
116	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
117	  const enchantmentSurcharge = sumSurcharges(
118	    step.items,
119	    enchantmentSurchargeForItem,
120	  );
121	  const discount =
122	    totalBasePremium * policyDiscountRate(customer, stepIndex);
123	  return {
124	    premium: Math.ceil(
125	      totalBasePremium + firstInsuranceSurcharge + curseSurcharge +
126	        enchantmentSurcharge - discount + PROCESSING_FEE,
127	    ),
128	  };
129	};
130	
131	export const processScenario = (scenario: Scenario): ScenarioResult => ({
132	  results: scenario.steps.map((step, index) =>
133	    "incident" in step
134	      ? claimStep(step)
135	      : quoteStep(step, scenario.customer, index),
136	  ),
137	});
